SELECT m.* FROM merchant m
LEFT JOIN category c ON m.merchant_id = c.merchant_id


        AND m.merchant_name LIKE CONCAT('%', #{merchantName}, '%')


        AND m.status = #{status}


        AND c.category_name = #{categoryName}


ORDER BY m.merchant_id DESC

mapper.update:
UPDATE merchant
merchant_name = #{merchantName}, cover_img = #{coverImg}, address = #{address}, score = #{score}, status = #{status}, alt = #{alt}, lat = #{lat}, lng = #{lng}
WHERE merchant_id = #{merchantId}
